INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc8440bbabc3a6b39bae7feb515405cbbf','off-season-by-brandon-knap','Off-Season by Brandon Knap','Branden Knap','A lot can happen during the off-season in wakeboarding. For most people this means swapping out the wakeboard for a snowboard or hibernating in the gym. For me, it meant moving from Rockford, Michigan to Orlando, Florida to chase progression. Off-season means something very different in Florida. The cables never stop spinning and the wetsuits come out. I treated the off-season as if it were the middle of the Summer, taking as many laps and road trips to cable parks as possible. This edit was all shot between October 2022 to April 2023. Temps ranged from 48 degrees up to 90 degrees. Parks in the edit include Orlando Watersports Complex, Nona Adventure Park, Valdosta Wake Compound, and Terminus Wake Park. Bring on the 2023 Season.','FILM'::"ContentType",'/home/hero-banner.jpg',142,2023,ARRAY['branden knap', 'cable']::text[],true,'PUBLISHED'::"PublishStatus",'2023-04-26T13:15:25.000Z'::timestamptz,'2023-04-26T13:15:25.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
