INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscf42f9b32f89279525433337da00ddeba','matty-muncey-winch-part-all-in','Matty Muncey Winch Part All In','Matty Muncy','Unique winching spots combined with stylish riding from Matty Muncey.','FILM'::"ContentType",'/home/hero-banner.jpg',312,2023,ARRAY['matty muncy']::text[],true,'PUBLISHED'::"PublishStatus",'2023-04-28T02:40:59.000Z'::timestamptz,'2023-04-28T02:40:59.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc1093ca7887df4ee75b18fd7faa6db964','skurfs-up','Skurf''s Up','Jerry Dugan','Rewind and watch Scott Byerly stick a 720. Pause to watch Dean Lavelle go bigger than ever. Frame by frame Greg Nelson taking style to a new level. Try a Mexican vacation with Shaun Murray and Cobe Mikacich or a Costa Rican adventure with Erik ''Gator'' Lutgert and Thomas Horrell. Whatever you fancy, you can''t afford to miss this film.','FILM'::"ContentType",'/home/hero-banner.jpg',1818,2023,ARRAY['jerry dugan']::text[],true,'PUBLISHED'::"PublishStatus",'2023-04-29T00:57:37.000Z'::timestamptz,'2023-04-29T00:57:37.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscca68639bef59f439d98e03e1c01f75c1','spray','Spray','Jerry Dugan','One of the original old school videos from FLF Films. This film features the top riders including Scot Byerly, Erik ''Gator'' Lutgert, Josh Smith, Bill McCaffray, Greg Nelson, Jeff Heer, Mike Weddington and Shannon Best. If you are into wakeboarding, this is a must-see.','FILM'::"ContentType",'/home/hero-banner.jpg',1991,2023,ARRAY['jerry dugan']::text[],true,'PUBLISHED'::"PublishStatus",'2023-04-29T00:57:38.000Z'::timestamptz,'2023-04-29T00:57:38.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
