INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usce0e7ba30c01b3bc11415b49f183b82bd','monkey-on-a-string','Monkey On A String','Jerry Dugan','FLF Films, in association with Ardoo Entertainment, traverses the United States and flies to the South Pacific to capture the best wakeboarders in their own environment. Featured wakeboarders include top pro riders like Wright, Watson, Byerly, Necrason, Gonzales, Murray, Mikacich, Owens, Ruck, Sharpe, Nunn, Harf, and Nelson. — FLF Films','FILM'::"ContentType",'/home/hero-banner.jpg',1602,2023,ARRAY['jerry dugan']::text[],true,'PUBLISHED'::"PublishStatus",'2023-04-29T03:44:59.000Z'::timestamptz,'2023-04-29T03:44:59.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc72900cbb11a35c42b6f28bcf6c3f9135','my-house','My House','Jerry Dugan','My House is considered to be one of the greatest wakeboard classics of all time. Check out some of the best riders including Shaun Murray, Gregg Necrason, Shawn Watson, Scott Byerly and many more!','FILM'::"ContentType",'/home/hero-banner.jpg',1801,2023,ARRAY['jerry dugan', 'classic']::text[],true,'PUBLISHED'::"PublishStatus",'2023-04-29T04:08:39.000Z'::timestamptz,'2023-04-29T04:08:39.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscd0684cfe844d7353619932ef26fa6e90','mayday','Mayday','Jerry Dugan','Every so often words or people become etched in stone, that summer ten of wakeboarding''s greatest riders found their way onto a houseboat for a two-week trip to etch their names in the stones of Lake Powell and be a part of the great wakeboard movie " MAYDAY''.','FILM'::"ContentType",'/home/hero-banner.jpg',2202,2023,ARRAY['jerry dugan', 'boat']::text[],true,'PUBLISHED'::"PublishStatus",'2023-04-29T05:16:38.000Z'::timestamptz,'2023-04-29T05:16:38.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
