INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscff3d550ba92512e3192afa91c6d42ee3','outhouse-the-deuce','Outhouse The Deuce','Derek Brown','Outhouse The Deuce is the second full length wakeboard film featuring Canada''s best riders. The crew travels from CWC in Philippines, across the U.S and to different parks in Canada. Can''t forget one of the last great boat sections to come from anyone in Canada! Riders Include: Riley Dillon Billy Allen Mickey Henry Dary Znebel Erika Langman Kelsey Chiappa Derek Brown Billy Allen Chris Sinkic Braden Ioi Scotty Boyson And pals!','FILM'::"ContentType",'/home/hero-banner.jpg',2089,2024,ARRAY['derek brown', 'boat']::text[],true,'PUBLISHED'::"PublishStatus",'2024-02-14T03:12:49.000Z'::timestamptz,'2024-02-14T03:12:49.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscd34d3d9e443013dbf7945afbce651262','outhouse-the-turd','Outhouse The Turd','Derek Brown','Outhouse returns with their third release, titled "The Turd." The Canadian team, featuring Jesse Jarrett, Derek Brown, Justin La Rue, Mickey Henry, Jordan Sullivan, Dylan Cook, Austin Farr, Dary Znebel, Riley Dillon, Liam Brearley, and others, is up to their classic antics as they tear through various locations in Canada, the US, and beyond in their latest full-length production. Kick back, unwind, and savor the action!','FILM'::"ContentType",'/home/hero-banner.jpg',2645,2024,ARRAY['derek brown', 'classic']::text[],true,'PUBLISHED'::"PublishStatus",'2024-02-14T14:50:57.000Z'::timestamptz,'2024-02-14T14:50:57.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc67d58cda259f8be8e2620e4087d68014','outhouse-end-of-the-roll','Outhouse End Of The Roll','Derek Brown','End of The Roll is the 4th full length wakeboard film produced by the Outhouse Wake crew. The Canadians have been working on his for a little over 2 years and is the culmination of a 7+ year journey of riding and filming together. The film is all about showing their collective passion for wakeboarding and how much fun they have together as a group. Traveling to Valdosta Wake Compound, West Rock Wake Park, and Elevated Wake Park, not to mention all of the unreal wake parks across Canada including Bayou Cable Park, Bluestone Wake Park, What Wake Park, Ranch Wake Park, and Rail Yard. Riders Include: Dary Znebel Riley Dillon Brennan Grange Liam Brearley Kat Sheriff Mickey Henry Austin Farr AKA Stan AKA Stanbacca Justin La Rue Derek Brown Jon Mctavish Nick Nags Kelsey Chiappa Andy Oke Kurtis Spencer And so many other Canadian Riders!','FILM'::"ContentType",'/home/hero-banner.jpg',3119,2024,ARRAY['derek brown', 'cable']::text[],true,'PUBLISHED'::"PublishStatus",'2024-02-14T19:50:20.000Z'::timestamptz,'2024-02-14T19:50:20.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc6c76d67da0b43e5dda257b87a428b012','outhouse','Outhouse',NULL,'The Outhouse crew started from an idea at the boat show and spawned into this full length wake film! The first wake movie to come out of Canada since the Muskoka Militia days almost a decade ago. Featuring: Brennan Grange, Derek Brown, Robbie McMillin, Kelsey Chiappa, Dary Znebel, Drew Austin, Erika Langman, and TV’s Mickey Henry as well as all the pals!','FILM'::"ContentType",'/home/hero-banner.jpg',2177,2024,ARRAY['boat']::text[],true,'PUBLISHED'::"PublishStatus",'2024-02-15T01:27:36.000Z'::timestamptz,'2024-02-15T01:27:36.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
