INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc30178bc649a5f4b8ed45c4441dadb18f','womens-wake-league','Women''s Wake League','Kitt Smith','The first ever Women''s Wake League (2023) went down and we''ve got the recap. Watch some of the best female riders in the world compete for the win!','FILM'::"ContentType",'/home/hero-banner.jpg',1120,2023,ARRAY['kitt smith']::text[],true,'PUBLISHED'::"PublishStatus",'2024-05-13T15:17:38.000Z'::timestamptz,'2024-05-13T15:17:38.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc72cf8e85ecbc49fb59b91c616b9e50df','welcome-to-the-zuu','Welcome To The Zuu','Zuupac','The Zuupack links up at Miami Watersports Complex!','FILM'::"ContentType",'/home/hero-banner.jpg',138,2024,ARRAY['zuupac']::text[],true,'PUBLISHED'::"PublishStatus",'2024-06-06T14:42:59.000Z'::timestamptz,'2024-06-06T14:42:59.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscc76e705ae5ed914de30198af11ad2dba','jungle-beats-zuupack','Jungle Beats – Zuupack','Zuupac','Tucked away in Florida’s wetlands, Revolution Cable Park keeps a low profile. With all hand- built features and hearts of transition, watch zuupack. run wild and leave their make on this hidden gem of a cable fresh outta quarantine.','FILM'::"ContentType",'/home/hero-banner.jpg',170,2024,ARRAY['zuupac', 'cable']::text[],true,'PUBLISHED'::"PublishStatus",'2024-06-06T14:43:36.000Z'::timestamptz,'2024-06-06T14:43:36.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscc23f6b74e7676bdeb4b1a40bfd1437a2','zuupacks-private-laps-at-revolution-cable-park','Zuupack''s Private Laps At Revolution Cable Park','Zuupac','Zuupacks drive west across Florida for Revolution Cable Park, an oasis of paradise. The boys are eager to shred, and it looks like someone let them out of their cages. New features constructed - the boys get down to what they do best. It''s a zuu thing.','FILM'::"ContentType",'/home/hero-banner.jpg',122,2024,ARRAY['zuupac', 'cable']::text[],true,'PUBLISHED'::"PublishStatus",'2024-06-06T14:44:34.000Z'::timestamptz,'2024-06-06T14:44:34.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc72a55486bae443f9db6e72e15974a463','primal-instinct-a-competitive-nature','Primal Instinct: A Competitive Nature','Zuupac','Watch Jonn Bonett preparing for a WWA Wake Park World Championship hosted at Valdosta Wake Compound . The competition side of our sport is just as wild as our video sections. The pressure can either eat you alive or chew you up enough to spit you back out on top after fighting your way through it all. Everybody comes to win, but actually doing what’s necessary is an entirely different story. The difference is in the Mindset.','FILM'::"ContentType",'/home/hero-banner.jpg',149,2024,ARRAY['zuupac', 'contest']::text[],true,'PUBLISHED'::"PublishStatus",'2024-06-06T14:45:43.000Z'::timestamptz,'2024-06-06T14:45:43.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
