INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscad7591c54606ba91cb3d43c5774b23ea','from-west-rock-with-love-by-zuupack','From West Rock With Love by Zuupack','Zuupac','Take some laps with the ZUU. in a blink or you’ll miss it style that has everyone throwing down across the lake out at West Rock Cable Park, Rockford, IL.','FILM'::"ContentType",'/home/hero-banner.jpg',398,2024,ARRAY['zuupac', 'cable']::text[],true,'PUBLISHED'::"PublishStatus",'2024-06-06T14:49:49.000Z'::timestamptz,'2024-06-06T14:49:49.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscd0300320eee34c29f813b340a8152fec','su-meile-aciu-lithuania','Su Meile; Ačiū Lithuania','Zuupac','Join ZUUPACK. on the trip of a lifetime across Lithuania.','FILM'::"ContentType",'/home/hero-banner.jpg',992,2024,ARRAY['zuupac']::text[],true,'PUBLISHED'::"PublishStatus",'2024-06-06T14:53:21.000Z'::timestamptz,'2024-06-06T14:53:21.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('usc8c202668df69cf5dbbeec38dab10b2ca','zuupack-call-of-the-wild','Zuupack – Call Of The Wild','Zuupac','6 dudes travel across the country together in search of some of the top spots for wakeboarding in America. Going a distance of 7711.8 miles, the boys set out in search of something bigger then themselves. They shred hard, meet some legendary locals, and had some fun along the way. This is their story.','FILM'::"ContentType",'/home/hero-banner.jpg',1358,2024,ARRAY['zuupac']::text[],true,'PUBLISHED'::"PublishStatus",'2024-06-06T14:57:51.000Z'::timestamptz,'2024-06-06T14:57:51.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
