INSERT INTO "ContentItem" ("id","slug","title","author","synopsis","type","posterUrl","durationSeconds","releaseYear","tags","isPremium","publishStatus","publishedAt","createdAt","updatedAt") VALUES ('uscb57bfe0817ad33636791283d92b4f760','yellow-hippie-ride-and-chill','Yellow Hippie Ride And Chill',NULL,'In 2025, a new film crew was formed to capture the real Asian wakeboard scene. Breaking away from the clean, refreshing image of wakeboarding, Yellow Hippie brings a dirty, raw, and street-style expression to the game. Everything — from the visuals to the apparel, logo, and flyers — is 100% original, spreading its impact far beyond the wakeboard industry.','FILM'::"ContentType",'/home/hero-banner.jpg',1955,2025,ARRAY[]::text[],true,'PUBLISHED'::"PublishStatus",'2025-11-20T01:34:20.000Z'::timestamptz,'2025-11-20T01:34:20.000Z'::timestamptz,now()) ON CONFLICT ("slug") DO UPDATE SET "title"=EXCLUDED."title","author"=EXCLUDED."author","synopsis"=EXCLUDED."synopsis","type"=EXCLUDED."type","posterUrl"=EXCLUDED."posterUrl","durationSeconds"=EXCLUDED."durationSeconds","releaseYear"=EXCLUDED."releaseYear","tags"=EXCLUDED."tags","isPremium"=EXCLUDED."isPremium","publishStatus"=EXCLUDED."publishStatus","publishedAt"=EXCLUDED."publishedAt","createdAt"=COALESCE("ContentItem"."createdAt", EXCLUDED."createdAt"),"updatedAt"=now();
